sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

    if (newValue == 'Healthy') {
        g_form.addInfoMessage('🌿 Great! This plant is thriving.');
    } else if (newValue == 'Needs_Attention') {
        g_form.addInfoMessage('🚨 Keep an eye on this plant and add notes.');
	} else if (newValue == 'Okay') {
        g_form.addInfoMessage('🪴 This plant is doing okay, but continue monitoring its health.');
    } else if (newValue == 'Sick') {
        g_form.addErrorMessage('🤒 This plant needs immediate care. Please document the issue in Notes.');
    } else if (newValue == 'Recovering') {
        g_form.addInfoMessage('🌱 This plant is recovering. Keep tracking progress.');
    } else if (newValue == 'Dead') {
        g_form.addErrorMessage('💀 This plant has died. Stop watering and update notes.');
    }
}
